package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;

import java.util.Collection;
import java.util.List;
import java.util.Set;

@AllArgsConstructor
public class VakbondsPremieResultatenVoorwaarden {

    private static final Set<Integer> VAKBONDSPREMIE_BEZOLDIGINGSCODE = ImmutableSet.of(1, 61);
    private static final Set<Integer> VAKBONDSPREMIE_BEZOLDIGINGSCODE_1ST_QUARTER = ImmutableSet.of(14, 15);

    private PersoonsDataManager persoonsDataManager;
    private LoonElementManager loonElementManager;
    private RekenTijd rekenTijd;

    public boolean test() {
        return hasKwartaalResultatenBezoldigingscodeVakbondsPremieWithBruto() || hasHuidigeMaandBezoldigingscodeVakbondsPremieWithBruto();
    }

    public boolean hasKwartaalResultatenBezoldigingscodeVakbondsPremieWithBruto() {
        // controleer maanden januari, februari, maart codes ingeboekt met een bezoldigingscode 1 of 61 waarbij bruto > 0
        List<RekenHoofd> kwartaalResultaten = persoonsDataManager.getKwartaalRekenResultaten();

        Money bedrag = kwartaalResultaten.stream()
                .filter(this::isNietHuidigeMaand)
                .map(RekenHoofd::getRekenLijnen).flatMap(Collection::stream)
                .filter(this::isBezoldigingsCodeVakbondspremie)
                .map(RekenLijn::getRekenBedragen).flatMap(Collection::stream)
                .filter(this::isBrutoBedrag)
                .map(RekenBedrag::getBedrag)
                .reduce(Money.ZERO, Money::add);
        return bedrag.signum() > 0;
    }

    private boolean isNietHuidigeMaand(RekenHoofd rekenHoofd) {
        return !rekenHoofd.getBeginDatum().equals(rekenTijd.beginDatum);
    }

    private boolean isBezoldigingsCodeVakbondspremie(RekenLijn lijn) {
        AardKodeExtensie looncode = lijn.getAardKodeExtensie();
        return isBezoldigingsCodeVakbondspremie(looncode);
    }

    private boolean isBezoldigingsCodeVakbondspremie(AardKodeExtensie looncode) {
        return isBezoldigingsCodeVakbondspremieAllYear(looncode) || isBezoldigingsCodeVakbondspremieFirstQuarter(looncode);
    }

    private boolean isBrutoBedrag(RekenBedrag rekenBedrag) {
        return rekenBedrag.getBedragType() == RekenBedragType.BRUTO_MAANDLOON;
    }

    private static boolean isBezoldigingsCodeVakbondspremieAllYear(AardKodeExtensie looncode) {
        return VAKBONDSPREMIE_BEZOLDIGINGSCODE.contains(looncode.getBezoldigingscode())
                || VAKBONDSPREMIE_BEZOLDIGINGSCODE.contains(looncode.getBezoldigingscodeVbn());
    }

    private boolean isBezoldigingsCodeVakbondspremieFirstQuarter(AardKodeExtensie looncode) {
        return TimeTools.bepaalKwartaal(rekenTijd.beginDatum) == 1 &&
                (VAKBONDSPREMIE_BEZOLDIGINGSCODE_1ST_QUARTER.contains(looncode.getBezoldigingscode())
                        || VAKBONDSPREMIE_BEZOLDIGINGSCODE_1ST_QUARTER.contains(looncode.getBezoldigingscodeVbn()));
    }

    public boolean hasHuidigeMaandBezoldigingscodeVakbondsPremieWithBruto() {
        Money brutoSum = loonElementManager.getPersoonsElementen().stream()
                .filter(element -> isBezoldigingsCodeVakbondspremie(element.getAardKodeExtensie()))
                .map(element -> element.getPropertyMoney(RekenBrutoKey.BRUTO_MAANDLOON_KEY))
                .reduce(Money.ZERO, Money::add);
        return brutoSum.signum() > 0;
    }
}
